import machine
import network
import ubinascii
import time
from umqtt.simple import MQTTClient

# Set up Wi-Fi connection
wlan = network.WLAN(network.STA_IF)
wlan.active(True)
wlan.connect('ssid', 'password')

while not wlan.isconnected():
    pass

# Set up sensor pin and readings
sensor_pin = machine.ADC(0) # replace with your temperature sensor's pin number
temperature_celsius = 27.5 # dummy data, use a temperature-sensing microcontroller to read actual temperature

# Set up MQTT connection
client_id = ubinascii.hexlify(machine.unique_id())
broker_ip = '192.168.1.100' # replace with your MQTT broker's IP address
topic = b"sensors/temp"

def sub_cb(topic, msg):
    print((topic.decode('utf-8'), msg.decode('utf-8')))

client = MQTTClient(client_id, broker_ip)
client.set_callback(sub_cb)
client.connect()
client.publish(topic, temperature_celsius) # publish the initial reading
client.subscribe(b"sensors/commands")  # subscribe to a specific topic

while True:
    # Read new temperature data from sensor (using a real temp sensor here for example)
    temperature_celsius = int(sensor_pin.read_u16() / 1000 * 1.22 - 500)

    # Publish new reading
    client.publish(topic, str(temperature_celsius))
    
    time.sleep(5) # adjust sleep interval as necessary

client.disconnect()